+// handles null oops
+static bool equal_oops(oop obj1, oop obj2) {
+  if (obj1 == obj2) {
+    return true;
+  }
+
+  if (obj1 != nullptr && obj2 != nullptr && obj1->klass() == obj2->klass() && obj1->is_inline_type()) {
+    InlineKlass* vk = InlineKlass::cast(obj1->klass());
+    return equal_value_objects(obj1, 0, obj2, 0, vk);
+  }
+  return false;
+}
